{
  "grammar": [
    {
      "pattern": "可以 + [action] + [object] + 嗎？",
      "structure": ["可以", "action", "object", "嗎"],
      "explanation_en": "Use '可以' (can/may) to politely ask for permission or request an action. This is a standard polite form in Taiwan.",
      "title": "Polite Request with 可以",
      "meaning": "May I...? / Can I...?",
      "when_to_use": ["When ordering at a café or shop", "When asking for permission to do something", "When making a polite request to a stranger or service staff"],
      "when_not_to_use": ["When speaking to close friends or family (use simpler forms)", "When giving commands or orders"],
      "pragmatic_notes": "In Taiwan, using '可以' is very common and polite. It's softer than '要' (want) and shows respect. Often combined with '不好意思' for extra politeness.",
      "word_order_notes": "The structure is fixed: 可以 + verb + object + 嗎. Do not place 嗎 before the verb.",
      "english_contrast": "English uses 'Can I...?' or 'May I...?' at the beginning. Chinese places '可以' at the start, followed by the action and object, then '嗎' at the end.",
      "korean_contrast": "Korean uses '~을/를 ~해도 될까요?' structure. Chinese is simpler with '可以...嗎?'.",
      "negative_examples": [
        {
          "text": "可以嗎喝咖啡？",
          "error": "Word order error: '嗎' should be at the end, not after '可以'."
        },
        {
          "text": "可以喝咖啡？",
          "error": "Missing '嗎' at the end makes it sound like a statement, not a polite question."
        }
      ],
      "incorrect_examples": [
        {
          "text": "可以喝咖啡？",
          "error": "Without '嗎', it's not a polite request but a casual question."
        }
      ],
      "transformation_drills": ["Change '可以喝咖啡嗎？' to '可以喝茶嗎？'", "Change '可以看菜單嗎？' to '可以看書嗎？'"],
      "production_drills": ["Ask for a menu politely", "Ask if you can sit here"],
      "common_error_patterns": ["Forgetting '嗎' at the end", "Placing object before verb"],
      "repair_feedback": {
        "word_order": "Remember: 可以 + action + object + 嗎",
        "politeness": "Adding '不好意思' before the request makes it even more polite",
        "vocabulary": "Use '可以' for polite requests, not '要' (want) which is more direct"
      }
    },
    {
      "pattern": "想要 + [object]",
      "structure": ["想要", "object"],
      "explanation_en": "Use '想要' (would like) to express a desire for an object politely. This is softer than '要' (want) and common in ordering.",
      "title": "Expressing Desire with 想要",
      "meaning": "I would like...",
      "when_to_use": ["When ordering food or drinks", "When expressing a preference in a shop", "When making a polite request for an item"],
      "when_not_to_use": ["When asking for permission (use 可以 instead)", "When giving commands"],
      "pragmatic_notes": "In Taiwan, '想要' is very common in service contexts. It's polite but not overly formal. Often used with '麻煩' (trouble) for extra politeness.",
      "word_order_notes": "Subject + 想要 + object. No additional verb needed. For example: '我想要一杯咖啡' (I would like a cup of coffee).",
      "english_contrast": "English uses 'I would like...' or 'I want...'. Chinese '想要' is similar to 'would like' in politeness level.",
      "korean_contrast": "Korean uses '~을/를 원합니다' or '~을/를 주세요'. Chinese '想要' is simpler and more direct.",
      "negative_examples": [
        {
          "text": "想要咖啡我",
          "error": "Word order error: subject should come before '想要'."
        },
        {
          "text": "我想要喝咖啡嗎？",
          "error": "Using '嗎' with '想要' is incorrect; '想要' is a statement, not a question."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我想要喝咖啡嗎？",
          "error": "Do not add '嗎' after '想要'; it's a statement of desire."
        }
      ],
      "transformation_drills": ["Change '我想要一杯水' to '我想要一杯茶'", "Change '我想要一個袋子' to '我想要一個杯子'"],
      "production_drills": ["Order a latte politely", "Say you would like a small cup of coffee"],
      "common_error_patterns": ["Adding '嗎' after '想要'", "Using '要' instead of '想要' (less polite)"],
      "repair_feedback": {
        "word_order": "Subject + 想要 + object",
        "politeness": "Use '想要' instead of '要' for a softer request",
        "vocabulary": "For objects, use measure words like '杯' for drinks, '個' for items"
      }
    },
    {
      "pattern": "不好意思 + [request]",
      "structure": ["不好意思", "request"],
      "explanation_en": "Use '不好意思' (excuse me / sorry to trouble) as a polite softener before any request. It shows consideration and is very common in Taiwan.",
      "title": "Polite Softener with 不好意思",
      "meaning": "Excuse me, but... / Sorry to trouble you...",
      "when_to_use": ["When starting a conversation with a stranger", "When making a request in a shop or café", "When interrupting someone", "When asking for help"],
      "when_not_to_use": ["When speaking to close friends (use '請問' or just state request)", "When the request is very casual"],
      "pragmatic_notes": "In Taiwan, '不好意思' is extremely common and versatile. It can mean 'excuse me', 'sorry', or 'thank you' depending on context. Using it before a request makes the interaction smoother and more polite.",
      "word_order_notes": "Place '不好意思' at the beginning of the sentence, followed by the request. For example: '不好意思，我想要一杯咖啡。'",
      "english_contrast": "English uses 'Excuse me' or 'Sorry to bother you' at the start. Chinese '不好意思' serves the same function but is more casual and frequent.",
      "korean_contrast": "Korean uses '실례합니다' or '죄송합니다' for similar politeness. '不好意思' is less formal than '죄송합니다'.",
      "negative_examples": [
        {
          "text": "我想要一杯咖啡不好意思",
          "error": "Word order error: '不好意思' should come before the request, not after."
        },
        {
          "text": "不好意思嗎我想要一杯咖啡",
          "error": "Do not add '嗎' after '不好意思'; it's not a question."
        }
      ],
      "incorrect_examples": [
        {
          "text": "不好意思嗎我想要一杯咖啡",
          "error": "Adding '嗎' after '不好意思' is incorrect; it's a softener, not a question word."
        }
      ],
      "transformation_drills": ["Add '不好意思' before '我想要一杯水'", "Add '不好意思' before '可以看菜單嗎？'"],
      "production_drills": ["Politely ask for a menu", "Politely ask for the price of a drink"],
      "common_error_patterns": ["Placing '不好意思' at the end of the sentence", "Using '不好意思' with '嗎'"],
      "repair_feedback": {
        "word_order": "Place '不好意思' at the beginning of the request",
        "politeness": "Always use '不好意思' when addressing service staff or strangers",
        "vocabulary": "Combine with '麻煩' for extra politeness in formal situations"
      }
    }
  ]
}
